}

// Simple Progress Circle (paid/total)
function ProgressCircle({ value }) {
  // value: 0-1
  const angle = 283 * value;
  return (
    <svg
      width="54"
      height="54"
      viewBox="0 0 36 36"
      style={{ marginTop: 0, marginBottom: 0 }}
    >
      <circle
        cx="18"
        cy="18"
        r="14"
        fill="#F8FAFF"
        stroke="#EAEDFB"
        strokeWidth="4"
      />
      <circle
        cx="18"
        cy="18"
        r="14"
        fill="none"
        stroke="#5D5FEF"
        strokeWidth="4"
        strokeDasharray={angle + " 360"}
        transform="rotate(-90 18 18)"
      />
      <text
        x="18"
        y="20"
        textAnchor="middle"
        alignmentBaseline="middle"
        fontSize="13"
        fontWeight="bold"
        fill="#5D5FEF"
      >
        80%
      </text>
    </svg>
  );
}
